		case 'viewRequests':
			$filename = 'vclViewRequests.js';
			$dojoRequires = array('dojo.parser',
			                      'dijit.form.DateTextBox',
			                      'dijit.form.TimeTextBox',
			                      'dijit.form.Select',
			                      'dojox.string.sprintf',
			                      'dijit.Dialog',
			                      'dijit.Menu',
